import{_ as e,o as i,c as l,a2 as r}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"常见问题","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/stock-transfer/faq.md","filePath":"zh-CN/stock-trading/stock-transfer/faq.md"}'),t={name:"stock-trading/stock-transfer/faq.md"};function o(h,a,n,d,s,c){return i(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><p>转仓进度优化建议、转仓失败原因、港美股转换方式及收费。</p><h2 id="转仓进度慢怎么办" tabindex="-1">转仓进度慢怎么办 <a class="header-anchor" href="#转仓进度慢怎么办" aria-label="Permalink to &quot;转仓进度慢怎么办&quot;">​</a></h2><p>如转仓时间较长，请按以下步骤自查：</p><h3 id="_1-确认双方券商均已提交申请" tabindex="-1">1. 确认双方券商均已提交申请 <a class="header-anchor" href="#_1-确认双方券商均已提交申请" aria-label="Permalink to &quot;1. 确认双方券商均已提交申请&quot;">​</a></h3><p>转仓需要在长桥和对方券商双方都提交申请。请确认：</p><ul><li>已在长桥 App 提交了转入/转出申请</li><li>已在对方券商提交了对应的转出/转入申请</li></ul><h3 id="_2-核实双方申请信息是否一致" tabindex="-1">2. 核实双方申请信息是否一致 <a class="header-anchor" href="#_2-核实双方申请信息是否一致" aria-label="Permalink to &quot;2. 核实双方申请信息是否一致&quot;">​</a></h3><p>常见信息错误导致转仓延误，请检查：</p><ul><li>姓名是否一致</li><li>证券账户号码是否正确</li><li>DTC / CCASS 代码是否正确</li><li>股票代码和数量是否双方一致</li></ul><p>如发现信息不一致，请修改后重新提交。</p><h3 id="_3-合并多支股票申请" tabindex="-1">3. 合并多支股票申请 <a class="header-anchor" href="#_3-合并多支股票申请" aria-label="Permalink to &quot;3. 合并多支股票申请&quot;">​</a></h3><p>如从同一券商转入多支股票，建议合并为一个申请提交，避免被转出方多次收取费用，也可提高转仓效率。如已分开提交，建议取消后重新合并提交。</p><h3 id="_4-联系对方券商" tabindex="-1">4. 联系对方券商 <a class="header-anchor" href="#_4-联系对方券商" aria-label="Permalink to &quot;4. 联系对方券商&quot;">​</a></h3><p>转仓进度取决于双方券商的沟通确认。请及时联系对方券商，确认对方已收到并开始处理转仓指示。</p><h2 id="常见转仓失败原因" tabindex="-1">常见转仓失败原因 <a class="header-anchor" href="#常见转仓失败原因" aria-label="Permalink to &quot;常见转仓失败原因&quot;">​</a></h2><ul><li>双方填写的股票数量不一致</li><li>对方券商信息（CCASS / DTC 代码）填写错误</li><li>未在对方券商提交转出申请</li><li>账户余额不足以支付转仓手续费</li><li>持仓股票尚未完成结算</li><li>账户处于融资状态</li></ul><h2 id="港美股转换" tabindex="-1">港美股转换 <a class="header-anchor" href="#港美股转换" aria-label="Permalink to &quot;港美股转换&quot;">​</a></h2><p>同一股票可在港股与美股市场之间转换（如 BABA 美股 ↔ 港股）。</p><h3 id="操作方式" tabindex="-1">操作方式 <a class="header-anchor" href="#操作方式" aria-label="Permalink to &quot;操作方式&quot;">​</a></h3><p>按邮件模板发送申请至 <a href="mailto:service@longbridge.hk" target="_blank" rel="noreferrer">service@longbridge.hk</a>，需包含：长桥证券账号、姓名、转换方向、转出股票代号、转出股票数量。</p><h3 id="收费" tabindex="-1">收费 <a class="header-anchor" href="#收费" aria-label="Permalink to &quot;收费&quot;">​</a></h3><p>美股转换港股：650 USD / 笔 + 0.5 USD / 股 + 其他第三方费用（如有）实报实销<br> 账户内须有足够金额以供扣付。</p><h3 id="处理时间" tabindex="-1">处理时间 <a class="header-anchor" href="#处理时间" aria-label="Permalink to &quot;处理时间&quot;">​</a></h3><p>申请提交成功后，一般 10-20 个工作日内完成，具体以上游处理为准。</p><h3 id="港美股转换风险说明" tabindex="-1">港美股转换风险说明 <a class="header-anchor" href="#港美股转换风险说明" aria-label="Permalink to &quot;港美股转换风险说明&quot;">​</a></h3><ul><li>指示一经发起后不可更改或取消</li><li>执行后相关股票及费用会被冻结及扣除，期间股票不能卖出/转仓/提取</li><li>股票冻结/扣除可能即时影响总资产值、保证金值、风控状态，须自行承担相关风险</li><li>不同股票兑换比例有别（如 BABA：1 美股 = 8 港股），如有疑问请联系客服查询</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading">股票交易</a></li><li><a href="/wiki/stock-trading/stock-transfer">股票转仓</a></li></ul>',29)])])}const f=e(t,[["render",o]]);export{p as __pageData,f as default};
